
import { Bar } from "vue-chartjs";

export default {
  extends: Bar,
  props: {
    chartData: {
      type: Array,
    },
  },
  data: () => ({
    options: {
      responsive: true,
      maintainAspectRatio: false,
      legend: {
        display: false,
      },
      scales: {
        yAxes: [
          {
            ticks: {
              beginAtZero: true,
            },
          },
        ],
      },
    },
  }),
  mounted() {
    const orgData = this.chartData.sort((a, b) => {
      let ca = a.skill.toUpperCase();
      let cb = b.skill.toUpperCase();

      if (ca < cb) {
        return -1;
      }
      if (ca > cb) {
        return 1;
      }

      return 0;
    });
    const dates = orgData.map((d) => d.skill);
    const totals = orgData.map((d) => d.total);

    this.renderChart(
      {
        labels: dates,
        datasets: [
          {
            data: totals,
            backgroundColor: "#d73333",
          },
        ],
      },
      this.options
    );
  },
};
